import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  HomeIcon,
  DocumentTextIcon,
  MapPinIcon,
  UserIcon,
  ArrowRightOnRectangleIcon,
  PlusCircleIcon,
  ChartBarIcon,
  ClockIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  Bars3Icon,
  XMarkIcon
} from '@heroicons/react/24/outline';

const Dashboard = () => {
  const [user, setUser] = useState(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [stats, setStats] = useState({
    totalComplaints: 0,
    pendingComplaints: 0,
    resolvedComplaints: 0,
    inProgressComplaints: 0
  });
  const [recentComplaints, setRecentComplaints] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    // Check if user is logged in
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    setUser(JSON.parse(userData));

    // Fetch dashboard data
    fetchDashboardData();
  }, [navigate]);

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/complaints/my', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        const complaints = data.complaints || [];

        // Calculate stats
        const stats = {
          totalComplaints: complaints.length,
          pendingComplaints: complaints.filter(c => c.status === 'pending').length,
          resolvedComplaints: complaints.filter(c => c.status === 'resolved').length,
          inProgressComplaints: complaints.filter(c => c.status === 'in-progress').length
        };

        setStats(stats);
        setRecentComplaints(complaints.slice(0, 5));
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  const getStatusBadge = (status) => {
    const colors = {
      'pending': 'bg-yellow-100 text-yellow-800',
      'in-progress': 'bg-blue-100 text-blue-800',
      'resolved': 'bg-green-100 text-green-800',
      'rejected': 'bg-red-100 text-red-800',
      'closed': 'bg-gray-100 text-gray-800'
    };
    return `inline-flex px-2 py-1 text-xs font-semibold rounded-full ${colors[status] || 'bg-gray-100 text-gray-800'}`;
  };

  const getPriorityBadge = (priority) => {
    const colors = {
      'low': 'bg-gray-100 text-gray-800',
      'medium': 'bg-orange-100 text-orange-800',
      'high': 'bg-red-100 text-red-800',
      'critical': 'bg-purple-100 text-purple-800'
    };
    return `inline-flex px-2 py-1 text-xs font-semibold rounded-full ${colors[priority] || 'bg-gray-100 text-gray-800'}`;
  };

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden font-sans">
      {/* Mobile Sidebar Toggle */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="p-4 bg-blue-600 text-white rounded-full shadow-2xl hover:bg-blue-700 transition-all active:scale-95"
        >
          {isMenuOpen ? <XMarkIcon className="h-6 w-6" /> : <Bars3Icon className="h-6 w-6" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white/80 backdrop-blur-xl border-r border-blue-100/50 shadow-2xl shadow-blue-500/5 transform transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] lg:relative lg:translate-x-0 ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'
        }`}>
        <div className="h-full flex flex-col">
          {/* Logo Section */}
          <div className="p-8 border-b border-blue-50/50 bg-gradient-to-br from-blue-50/30 to-white/50">
            <Link to="/" className="flex items-center space-x-3 group relative">
              <div className="absolute -inset-2 bg-blue-100/20 rounded-2xl scale-75 opacity-0 group-hover:opacity-100 group-hover:scale-110 transition-all duration-500 blur-xl"></div>
              <div className="relative w-11 h-11 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200 group-hover:shadow-blue-300 transition-all duration-500 group-hover:-rotate-6">
                <MapPinIcon className="h-6 w-6 text-white" />
              </div>
              <div className="relative">
                <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none">
                  Urban<span className="text-blue-600 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Insights</span>
                </h1>
                <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mt-1.5 opacity-80">Citizen Portal</p>
              </div>
            </Link>
          </div>

          {/* User Profile Section (Top) */}
          <div className="px-6 py-8">
            <div className="p-4 bg-gradient-to-br from-blue-50/50 to-indigo-50/50 rounded-[1.5rem] border border-blue-100/50 flex items-center space-x-4 hover:shadow-xl hover:shadow-blue-500/5 transition-all duration-300">
              <div className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-r from-blue-400 to-indigo-400 rounded-full opacity-20 group-hover:opacity-40 blur transition duration-500"></div>
                <div className="relative w-12 h-12 bg-white rounded-full flex items-center justify-center border-2 border-blue-100 shadow-sm flex-shrink-0 transition-transform duration-500 group-hover:scale-110">
                  <UserIcon className="h-6 w-6 text-blue-600" />
                </div>
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-black text-gray-900 truncate">
                  {user?.name || 'Citizen User'}
                </p>
                <p className="text-[11px] font-medium text-blue-500/80 truncate">
                  {user?.email || 'Authenticated'}
                </p>
              </div>
            </div>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 px-4 py-2 space-y-1.5 overflow-y-auto custom-scrollbar">
            <Link
              to="/dashboard"
              className="group flex items-center space-x-3 px-5 py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20 transition-all duration-300 hover:scale-[1.02] active:scale-95"
            >
              <HomeIcon className="h-5 w-5 transition-transform group-hover:scale-110" />
              <span className="tracking-tight">Overview</span>
            </Link>
            <Link
              to="/complaint-history"
              className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1"
            >
              <ClockIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">Complaint History</span>
            </Link>
            <Link
              to="/submit-complaint"
              className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1"
            >
              <PlusCircleIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">New Incident</span>
            </Link>
          </nav>

          {/* Sign Out Section (Bottom) */}
          <div className="p-6">
            <button
              onClick={handleLogout}
              className="w-full group flex items-center justify-center space-x-2 py-4 px-4 rounded-2xl text-[13px] font-black text-red-500 hover:text-white hover:bg-red-500 border border-red-100/50 transition-all duration-300 active:scale-95 shadow-lg shadow-red-500/5 bg-white/50 backdrop-blur-sm"
            >
              <ArrowRightOnRectangleIcon className="h-5 w-5 transition-transform group-hover:-translate-x-1" />
              <span className="uppercase tracking-widest">Sign Out</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Overlay for mobile sidebar */}
      {isMenuOpen && (
        <div
          className="lg:hidden fixed inset-0 bg-gray-900/40 backdrop-blur-sm z-30 transition-opacity"
          onClick={() => setIsMenuOpen(false)}
        ></div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 h-full overflow-y-auto bg-gray-50">
        <div className="max-w-6xl mx-auto px-6 lg:px-10 py-10">
          {/* Welcome Header */}
          {/* Welcome Section */}
          <header className="mb-12 flex flex-col md:flex-row md:items-end md:justify-between gap-4">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">
                Welcome back, {user?.name || 'User'}!
              </h1>
              <p className="text-gray-600 mt-2">Here's what's happening with your complaints today.</p>
            </div>
            <Link
              to="/submit-complaint"
              className="inline-flex items-center px-6 py-3 bg-blue-600 text-white rounded-2xl text-sm font-bold hover:bg-blue-700 transition-all shadow-xl hover:shadow-blue-200 active:scale-95"
            >
              <PlusCircleIcon className="h-5 w-5 mr-2" />
              Report New Issue
            </Link>
          </header>

          {/* Stats Grid */}
          <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
            {[
              { label: 'Total Files', val: stats.totalComplaints, icon: DocumentTextIcon, color: 'blue' },
              { label: 'Pending', val: stats.pendingComplaints, icon: ClockIcon, color: 'amber' },
              { label: 'Resolved', val: stats.resolvedComplaints, icon: CheckCircleIcon, color: 'emerald' },
              { label: 'High Priority', val: stats.inProgressComplaints, icon: ExclamationTriangleIcon, color: 'rose' }
            ].map((stat, i) => (
              <div key={i} className="group p-6 bg-white rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-md transition-all hover:-translate-y-1">
                <div className="flex items-center justify-between mb-4">
                  <div className={`p-3 rounded-2xl bg-${stat.color}-50 text-${stat.color}-600`}>
                    <stat.icon className="h-6 w-6" />
                  </div>
                  <span className="text-[10px] font-semibold text-gray-300 uppercase tracking-widest group-hover:text-blue-400 transition-colors">Visual Stats</span>
                </div>
                <p className="text-3xl font-bold text-gray-900 mb-1">{stat.val}</p>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-tighter">{stat.label}</p>
              </div>
            ))}
          </section>

          {/* Recent Complaints Section */}
          <section className="bg-white rounded-[2.5rem] border border-gray-100 shadow-sm overflow-hidden p-2">
            <div className="px-8 py-6 mb-2 border-b border-gray-50 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-gray-900">Recent Activity</h3>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-widest mt-1">Last 5 submissions</p>
              </div>
              <Link
                to="/complaint-history"
                className="px-5 py-2 rounded-xl text-xs font-bold text-blue-600 hover:bg-blue-50 transition-all"
              >
                View Analytics History
              </Link>
            </div>

            <div className="overflow-x-auto">
              {recentComplaints.length > 0 ? (
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b border-gray-50">
                      <th className="px-8 py-4 text-[10px] font-bold text-gray-400 uppercase">Description</th>
                      <th className="px-8 py-4 text-[10px] font-bold text-gray-400 uppercase">Category</th>
                      <th className="px-8 py-4 text-[10px] font-bold text-gray-400 uppercase">Current Status</th>
                      <th className="px-8 py-4 text-[10px] font-bold text-gray-400 uppercase">Impact</th>
                      <th className="px-8 py-4 text-right text-[10px] font-bold text-gray-400 uppercase">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {recentComplaints.map((complaint) => (
                      <tr key={complaint._id} className="hover:bg-gray-50/50 transition-colors group">
                        <td className="px-8 py-5">
                          <p className="text-sm font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{complaint.title}</p>
                          <p className="text-[10px] text-gray-400 font-medium mt-0.5">{new Date(complaint.createdAt).toLocaleDateString()}</p>
                        </td>
                        <td className="px-8 py-5">
                          <span className="px-3 py-1 bg-gray-100 text-gray-600 rounded-lg text-xs font-bold uppercase tracking-tighter">
                            {complaint.category}
                          </span>
                        </td>
                        <td className="px-8 py-5">
                          <span className={`${getStatusBadge(complaint.status)} px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest`}>
                            {complaint.status}
                          </span>
                        </td>
                        <td className="px-8 py-5">
                          <span className={`${getPriorityBadge(complaint.priority)} px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest`}>
                            {complaint.priority}
                          </span>
                        </td>
                        <td className="px-8 py-5 text-right">
                          <Link
                            to="/complaint-history"
                            className="inline-flex items-center px-4 py-2 bg-white border border-gray-200 rounded-xl text-[10px] font-bold text-gray-600 hover:border-blue-200 hover:text-blue-600 hover:shadow-sm transition-all shadow-sm"
                          >
                            Details
                          </Link>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <div className="px-8 py-20 text-center">
                  <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <DocumentTextIcon className="h-8 w-8 text-gray-300" />
                  </div>
                  <h3 className="text-lg font-bold text-gray-900 mb-2">No Community Reports Found</h3>
                  <p className="text-sm text-gray-400 max-w-xs mx-auto mb-8 font-medium">Your reports will help your community grow. Start by sharing an issue you've encountered.</p>
                  <Link
                    to="/submit-complaint"
                    className="inline-flex items-center px-8 py-3 bg-blue-600 text-white rounded-2xl text-sm font-bold hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95 transition-all"
                  >
                    <PlusCircleIcon className="h-5 w-5 mr-2" />
                    Submit First Report
                  </Link>
                </div>
              )}
            </div>
          </section>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
